const body = $input.first().json.body ?? $input.first().json;
const score = body.confluenceScore ?? 50;
return [{
  json: {
    master: {
      summary: `WIN: índice Bovespa com confluence ${score}/100. Foco em abertura e fluxo institucional.`,
      strengths: body.positive ?? [],
      weaknesses: body.negative ?? [],
      probability: score >= 65 ? 'Elevada' : 'Moderada',
      risk: 'Volatilidade intraday'
    },
    agentInsights: [
      ...(body.agentInsights ?? []),
      {
        agentId: 'win-specialist',
        asset: 'WIN',
        specialization: 'Mini Índice Bovespa',
        summary: `Setup WIN — ${body.recommendation ?? 'Neutro'}`,
        highlights: [`Score ${score}`, ...(body.zones ?? []).slice(0,2).map(z => z.label)]
      }
    ]
  }
}];
